from geosat.tools.urlprotocol import UrlReader, UrlProtocols

from geosat.psanp.abstractions import bundler
from geosat.psanp.abstractions.bundler import Bundle
from geosat.psanp.abstractions.utils import find_in_bundle_folder


def get_bundle_classifier_from_name(bundle_name: str) -> Bundle:
    bundle_path: str = find_in_bundle_folder(f"{bundle_name}.zip")
    with UrlReader(bundle_path, UrlProtocols()) as reader:
        bundled = bundler.from_file(reader)
    return bundled
